from dataclasses import dataclass

@dataclass
class OutputPolicy:
    block_if_critical: bool = True       # block response if any critical PII survives
    max_redactions_before_block: int = 10  # block if too many redactions (likely a bulk data leak)
    allow_pseudonymised_persons: bool = True

class PolicyViolationError(Exception):
    pass

def enforce_output_policy(
    sanitised_text: str,
    redaction_map: "RedactionMap",
    scan_result: "ScanResult",
    policy: OutputPolicy = OutputPolicy(),
) -> str:
    """
    Apply output policy rules. Returns sanitised text if allowed.
    Raises PolicyViolationError if the response should be blocked.
    """
    critical_surviving = [
        f for f in scan_result.findings
        if f.entity_type in {"SSN", "CREDIT_CARD", "API_KEY", "HEALTH_DATA"}
    ]
    if policy.block_if_critical and critical_surviving:
        types = [f.entity_type for f in critical_surviving]
        raise PolicyViolationError(
            f"Response blocked: critical PII survived redaction ({types})"
        )

    if len(redaction_map.entries) > policy.max_redactions_before_block:
        raise PolicyViolationError(
            f"Response blocked: {len(redaction_map.entries)} redactions exceed policy "
            f"limit of {policy.max_redactions_before_block} (possible bulk data leak)"
        )

    return sanitised_text
